@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_isLoading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search-error">
            <span>Search failed: @_error</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (_hasSearched && _results.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }
    else if (_results.Count > 0)
    {
        <div class="product-search-results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => OnProductSelected.InvokeAsync(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" loading="lazy" />
                    <div class="product-card-body">
                        <h3>@product.Name</h3>
                        <p>@product.Price.ToString("C")</p>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product> _results = new();
    private bool _isLoading;
    private bool _hasSearched;
    private string? _error;

    private CancellationTokenSource? _debounceCts;
    private CancellationTokenSource? _searchCts;
    private Timer? _debounceTimer;

    private void OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;

        // Cancel any pending debounce and in-flight search.
        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        _debounceCts = new CancellationTokenSource();

        CancelInflightSearch();

        var captured = _query;
        var linkedCts = _debounceCts;

        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(_ =>
        {
            if (!linkedCts.IsCancellationRequested)
            {
                _ = InvokeAsync(() => ExecuteSearchAsync(captured));
            }
        }, null, 300, Timeout.Infinite);
    }

    private async Task ExecuteSearchAsync(string query)
    {
        if (string.IsNullOrWhiteSpace(query))
        {
            _results = new();
            _hasSearched = false;
            _error = null;
            _isLoading = false;
            StateHasChanged();
            return;
        }

        CancelInflightSearch();
        _searchCts = new CancellationTokenSource();
        var ct = _searchCts.Token;

        _isLoading = true;
        _error = null;
        StateHasChanged();

        try
        {
            _results = await ProductService.SearchAsync(query, ct);
            _hasSearched = true;
            _error = null;
        }
        catch (OperationCanceledException)
        {
            // Search was superseded by a newer query; do nothing.
            return;
        }
        catch (Exception ex)
        {
            _results = new();
            _error = ex.Message;
        }
        finally
        {
            if (!ct.IsCancellationRequested)
            {
                _isLoading = false;
                StateHasChanged();
            }
        }
    }

    private async Task RetrySearch()
    {
        await ExecuteSearchAsync(_query);
    }

    private void CancelInflightSearch()
    {
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = null;
    }

    public void Dispose()
    {
        _debounceTimer?.Dispose();
        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        CancelInflightSearch();
    }
}

